SELECT MAX(pga) AS max_pga
FROM model_results
WHERE event_id = 123456;

SELECT AVG(rsd595) AS average_rsd595
FROM earthquake_events
WHERE event_id = 12345;

SELECT MAX(rup_mag) AS max_magnitude
FROM earthquake_events
WHERE event_date LIKE '2023-%';

SELECT site_location
FROM site_conditions
ORDER BY site_location ASC;

SELECT event_id, MAX(dist_rrup) AS max_distance
FROM earthquake_events
GROUP BY event_id;

SELECT fault_type, MAX(rup_mag) AS max_magnitude
FROM earthquake_events
GROUP BY fault_type;

SELECT AVG(rsd595) AS avg_rsd595, AVG(rsd575) AS avg_rsd575
FROM earthquake_events
WHERE event_id = 1234;
